using System;

class Vehicle
{
    public string Brand { get; set; }
    public int Speed { get; set; }

    public Vehicle(string brand, int speed)
    {
        Brand = brand;
        Speed = speed;
    }

    public void DisplayInfo()
    {
        Console.WriteLine($"Nəqliyyat vasitəsi: {Brand}, Sürət: {Speed} km/saat");
    }
}

class Car : Vehicle
{
    public int Doors { get; set; }

    public Car(string brand, int speed, int doors) : base(brand, speed)
    {
        Doors = doors;
    }
}

class Program
{
    static void Main(string[] args)
    {
        Car car = new Car("Toyota", 120, 4);
        car.DisplayInfo();
        Console.WriteLine($"Qapılar: {car.Doors}");
    }
}
// Output:
// Nəqliyyat vasitəsi: Toyota, Sürət: 120 km/saat
// Qapılar: 4

using System;

class Animal
{
    public virtual void MakeSound()
    {
        Console.WriteLine("Heyvan səsi çıxarır.");
    }
}

class Dog : Animal
{
    public override void MakeSound()
    {
        Console.WriteLine("İt: Hav-hav!");
    }
}

class Cat : Animal
{
    public override void MakeSound()
    {
        Console.WriteLine("Pişik: Miyav!");
    }
}

class Program
{
    static void Main(string[] args)
    {
        Animal animal = new Animal();
        Animal dog = new Dog();
        Animal cat = new Cat();

        animal.MakeSound();
        dog.MakeSound();
        cat.MakeSound();
    }
}
// Output:
// Heyvan səsi çıxarır.
// İt: Hav-hav!
// Pişik: Miyav!

using System;

class BankAccount
{
    protected decimal balance;

    public BankAccount(decimal initialBalance)
    {
        balance = initialBalance;
    }

    public virtual void DisplayBalance()
    {
        Console.WriteLine($"Balans: {balance}");
    }
}

class SavingsAccount : BankAccount
{
    public SavingsAccount(decimal initialBalance) : base(initialBalance)
    {
    }

    public override void DisplayBalance()
    {
        Console.WriteLine($"Əmanət hesabının balansı: {balance}");
    }

    public void AddInterest(decimal rate)
    {
        balance += balance * rate;
    }
}

class Program
{
    static void Main(string[] args)
    {
        SavingsAccount account = new SavingsAccount(1000);
        account.DisplayBalance();
        account.AddInterest(0.05m);
        account.DisplayBalance();
    }
}
// Output:
// Əmanət hesabının balansı: 1000
// Əmanət hesabının balansı: 1050

